public class Main {
    public static void main(String[] args) {
        // for dongusu
        System.out.println("1'den 5'e kadar:");
        for (int i = 1; i <= 5; i++) {
            System.out.println("Sayi: " + i);
        }

        // while dongusu
        System.out.println("\nGeri sayim:");
        int counter = 5;
        while (counter > 0) {
            System.out.println(counter);
            counter--;
        }

        // for-each dongusu
        System.out.println("\nMeyveler:");
        String[] fruits = {"Elma", "Armut", "Muz", "Karpuz"};
        for (String fruit : fruits) {
            System.out.println("- " + fruit);
        }

        // do-while dongusu
        System.out.println("\nDo-while ornegi:");
        int n = 0;
        do {
            System.out.println("n = " + n);
            n++;
        } while (n < 3);
    }
}
